export type Result<T extends object = object> =
    | ({ ok: true } & T)
    | { ok: false; error: string };

export interface SwStatus {
    state: 'none' | 'installing' | 'active';
    scope?: string;
    scriptURL?: string;
    hasWaiting?: boolean;
    waitingScriptURL?: string;
}

async function getRegistration(): Promise<ServiceWorkerRegistration | undefined> {
    if (!('serviceWorker' in navigator)) return undefined;
    return navigator.serviceWorker.getRegistration();
}

export async function getSwStatus(): Promise<Result<SwStatus>> {
    try {
        const reg = await getRegistration();
        if (!reg) return { ok: true, state: 'none' };

        const active = reg.active;
        const waiting = reg.waiting;
        const installing = reg.installing;

        if (active) {
            return {
                ok: true,
                state: 'active',
                scope: reg.scope,
                scriptURL: active.scriptURL,
                hasWaiting: !!waiting,
                ...(waiting ? { waitingScriptURL: waiting.scriptURL } : {}),
            };
        }
        if (installing) {
            return { ok: true, state: 'installing', scope: reg.scope, scriptURL: installing.scriptURL };
        }
        return { ok: true, state: 'none', scope: reg.scope };
    } catch (err) {
        return { ok: false, error: formatError(err) };
    }
}

export async function unregisterSw(): Promise<Result<{ unregistered: boolean }>> {
    try {
        const reg = await getRegistration();
        if (!reg) return { ok: false, error: 'No service worker registration' };
        const unregistered = await reg.unregister();
        return { ok: true, unregistered };
    } catch (err) {
        return { ok: false, error: formatError(err) };
    }
}

export async function updateSw(): Promise<Result> {
    try {
        const reg = await getRegistration();
        if (!reg) return { ok: false, error: 'No service worker registration' };
        await reg.update();
        return { ok: true };
    } catch (err) {
        return { ok: false, error: formatError(err) };
    }
}

export async function skipWaiting(): Promise<Result> {
    try {
        const reg = await getRegistration();
        if (!reg) return { ok: false, error: 'No service worker registration' };
        if (!reg.waiting) return { ok: false, error: 'No waiting service worker' };
        reg.waiting.postMessage({ type: 'SKIP_WAITING' });
        return { ok: true };
    } catch (err) {
        return { ok: false, error: formatError(err) };
    }
}

function formatError(err: unknown): string {
    if (err instanceof Error) return err.stack ?? err.message;
    return String(err);
}
